    {以下循环查找 p 在队列中的确切位置}
    While(p.Priority < p1.Priority) And (p1.Next <> Null) Do
    Begin
        p2 := p1;
        p1 := p1.Next;
    End;
    {将 p 插入到就绪队列中}
    p.Next := p1;
    p2.Next := p;
End;
